1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	interface QuoteStep {
11	  op: "quote";
12	  items: { type: string }[];
13	}
14	
15	interface Scenario {
16	  customer: { yearsWithMHPCO: number };
17	  steps: QuoteStep[];
18	}
19	
20	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
21	  const results = scenario.steps.map((step) => {
22	    const policyBase = step.items.reduce(
23	      (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
24	      0,
25	    );
26	    const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
27	    const premium = Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
28	    return { premium };
29	  });
30	  return { results };
31	};
